-- ============================================================
-- 20260601000017_cleanup_and_passage.sql
-- 1) Add `context` column to questions (shared passage text for grouped blanks).
-- 2) Delete every exam EXCEPT the ones imported from the Mai Lan Hương file.
-- ============================================================

alter table questions add column if not exists context text;

delete from exams where id not in (
  '77777777-7777-7777-7777-777777777777', -- I
  '55555555-5555-5555-5555-555555555555', -- XX
  '66666666-6666-6666-6666-666666666666', -- XXV
  'a0000002-0000-4000-8000-000000000000', -- II
  'a0000003-0000-4000-8000-000000000000', -- III
  'a0000004-0000-4000-8000-000000000000', -- IV
  'a0000005-0000-4000-8000-000000000000', -- V
  'a0000006-0000-4000-8000-000000000000', -- VI
  'a0000007-0000-4000-8000-000000000000', -- VII
  'a0000008-0000-4000-8000-000000000000', -- VIII
  'a0000009-0000-4000-8000-000000000000', -- IX
  'a0000010-0000-4000-8000-000000000000', -- X
  'a0000011-0000-4000-8000-000000000000', -- XI
  'a0000012-0000-4000-8000-000000000000', -- XII
  'a0000013-0000-4000-8000-000000000000', -- XIII
